// Trier par date décroissante et limiter à 10 articles
const items = $input.all();

// Dédupliquer par titre
const seen = new Set();
const unique = items.filter(item => {
  const title = (item.json.title || '').toLowerCase().trim();
  if (seen.has(title)) return false;
  seen.add(title);
  return true;
});

// Trier par date décroissante
const sorted = unique.sort((a, b) => {
  const dateA = new Date(a.json.pubDate || a.json.isoDate || 0);
  const dateB = new Date(b.json.pubDate || b.json.isoDate || 0);
  return dateB - dateA;
});

// Prendre les 10 premiers
const top10 = sorted.slice(0, 10);

const today = new Date().toLocaleDateString('fr-FR', {
  weekday: 'long',
  year: 'numeric',
  month: 'long',
  day: 'numeric'
});

// Formater les articles pour le prompt
const articlesText = top10.map((item, i) => {
  const title = (item.json.title || 'Sans titre').replace(/[\"]/g, "'");
  const link = item.json.link || 'N/A';
  const snippet = (item.json.contentSnippet || item.json.content || '').substring(0, 200).replace(/[\"]/g, "'").replace(/\n/g, ' ');
  return `${i + 1}. ${title} - Source: ${link} - ${snippet}`;
}).join('\n');

const userPrompt = `Voici les ${top10.length} actualités tech les plus marquantes du ${today} :\n\n${articlesText}\n\n---\nÀ partir de ces actualités, rédige un article de blog en français (400-600 mots) qui : 1. A un titre accrocheur avec un emoji 2. Commence par une introduction engageante 3. Couvre les 3-5 sujets les plus intéressants avec des sous-titres 4. Pour chaque sujet un paragraphe de contexte et pourquoi c est important 5. Termine par une conclusion 6. Ajoute une section Sources à la fin avec les liens vers les articles originaux`;

// Construire le body OpenAI complet comme objet JS (pas de problème d'échappement)
const openaiBody = {
  model: 'gpt-4o-mini',
  temperature: 0.7,
  max_tokens: 2000,
  messages: [
    {
      role: 'system',
      content: 'Tu es un rédacteur de blog tech francophone spécialisé dans le développement web, l IA et les nouvelles technologies. Tu rédiges des articles engageants, accessibles et bien structurés en français. Ton ton est professionnel mais décontracté. Tu utilises le format Markdown.'
    },
    {
      role: 'user',
      content: userPrompt
    }
  ]
};

return [{
  json: {
    openaiBody,
    date: today,
    articleCount: top10.length
  }
}];
